let amountRowCounter=0;let ruleRowCounter=0;const HISTORY_KEY='pointCalculatorHistoryV3';document.addEventListener('DOMContentLoaded',function(){addAmountRow();updateAmountSummary();loadHistory();});function addAmountRow(){const amountList=document.getElementById('amount-list');const rowId='amount-row-'+(++amountRowCounter);const row=document.createElement('tr');row.id=rowId;row.innerHTML=`<td><div class="amount-target-editor"><select id="${rowId}-mode"class="simple-select"style="width: 170px;"onchange="updateAmountRowMode('${rowId}')"><option value="count">◯回分</option><option value="range">◯回から◯回まで</option></select><div id="${rowId}-fields"class="amount-target-line"></div></div></td><td><div class="amount-price-line"><input type="number"id="${rowId}-amount"class="simple-inputtext"style="width: 180px;"min="0"step="1"value=""oninput="updateAmountSummary()"><span>円</span></div></td><td id="${rowId}-count">1件</td><td><button type="button"class="round-rect-button small-button"onclick="removeAmountRow('${rowId}')"><div class="middle-text">削除</div></button></td>`;amountList.appendChild(row);updateAmountRowMode(rowId);resequenceAmountRows();updateAmountSummary();}
function removeAmountRow(rowId){const amountList=document.getElementById('amount-list');if(amountList.children.length<=1){document.getElementById(rowId+'-mode').value='count';updateAmountRowMode(rowId);document.getElementById(rowId+'-count-input').value=1;document.getElementById(rowId+'-amount').value='';updateAmountSummary();return;}
const row=document.getElementById(rowId);if(row){row.remove();}
resequenceAmountRows();updateAmountSummary();}
function updateAmountRowMode(rowId){const mode=document.getElementById(rowId+'-mode').value;const fields=document.getElementById(rowId+'-fields');if(mode==='range'){fields.innerHTML=`<input type="number"id="${rowId}-start"class="simple-inputtext"style="width: 80px;"min="1"step="1"value="1"oninput="updateAmountSummary()"><span>回から</span><input type="number"id="${rowId}-end"class="simple-inputtext"style="width: 80px;"min="1"step="1"value="1"oninput="updateAmountSummary()"><span>回まで</span>`;updateAmountSummary();return;}
fields.innerHTML=`<input type="number"id="${rowId}-count-input"class="simple-inputtext"style="width: 80px;"min="1"step="1"value="1"oninput="updateAmountSummary()"><span>回分</span>`;updateAmountSummary();}
function resequenceAmountRows(){const rows=document.querySelectorAll('#amount-list tr');let expectedStart=1;rows.forEach(function(row,index){const range=getAmountRowRange(row,expectedStart);const countCell=document.getElementById(row.id+'-count');if(range.valid){countCell.textContent=(range.end-range.start+1)+'件';expectedStart=range.end+1;}else{countCell.textContent='-';}
row.dataset.order=String(index+1);});}
function updateAmountSummary(){const summary=document.getElementById('amount-summary');const rows=document.querySelectorAll('#amount-list tr');let totalCount=0;let totalAmount=0;let validRows=0;let expectedStart=1;rows.forEach(function(row){const range=getAmountRowRange(row,expectedStart);const amount=parseFloat(document.getElementById(row.id+'-amount').value);const countCell=document.getElementById(row.id+'-count');if(range.valid){const count=range.end-range.start+1;countCell.textContent=count+'件';if(!isNaN(amount)&&amount>0){totalCount+=count;totalAmount+=amount*count;validRows+=1;}
expectedStart=range.end+1;}else{countCell.textContent='-';}});if(validRows===0){summary.innerHTML='有効な利用回数範囲と利用金額を入力すると、ここに件数と合計金額を表示します。';return;}
summary.innerHTML=`<p><strong>${validRows}件の明細</strong></p><p>合計利用回数:${formatNumber(totalCount)}回</p><p>合計利用金額:${formatNumber(totalAmount)}円</p>`;}
function getAmountRowRange(row,expectedStart){const mode=document.getElementById(row.id+'-mode').value;if(mode==='range'){const start=parseInt(document.getElementById(row.id+'-start').value,10);const end=parseInt(document.getElementById(row.id+'-end').value,10);const valid=!isNaN(start)&&!isNaN(end)&&start>=1&&end>=start&&start===expectedStart;return{valid:valid,start:start,end:end};}
const count=parseInt(document.getElementById(row.id+'-count-input').value,10);const valid=!isNaN(count)&&count>=1;return{valid:valid,start:expectedStart,end:valid?expectedStart+count-1:expectedStart};}
function addRuleRow(){const ruleList=document.getElementById('rule-list');const ruleId='rule-row-'+(++ruleRowCounter);const row=document.createElement('tr');row.id=ruleId;row.innerHTML=`<td><select class="simple-select"id="${ruleId}-type"onchange="updateRuleRow('${ruleId}')"style="width: 240px;"><option value="range">回数範囲で還元率を変更</option><option value="all_after">一定回数以上で一律変更</option><option value="first_n">最初の回数だけ変更</option></select></td><td id="${ruleId}-fields"></td><td><button type="button"class="round-rect-button small-button"onclick="removeRuleRow('${ruleId}')"><div class="middle-text">削除</div></button></td>`;ruleList.appendChild(row);updateRuleRow(ruleId);}
function removeRuleRow(ruleId){const row=document.getElementById(ruleId);if(row){row.remove();}}
function updateRuleRow(ruleId){const type=document.getElementById(ruleId+'-type').value;const fields=document.getElementById(ruleId+'-fields');if(type==='range'){fields.innerHTML=`<div class="rule-range-line"><input type="number"id="${ruleId}-start"class="simple-inputtext"style="width: 90px;"min="1"step="1"value="2"><span>回から</span><input type="number"id="${ruleId}-end"class="simple-inputtext"style="width: 90px;"min="1"step="1"value="5"><span>回まで</span><label class="inline-fields no-wrap"style="gap: 4px;"><input type="checkbox"id="${ruleId}-open"onchange="toggleRuleOpenEnd('${ruleId}')"><span>以降全て</span></label><input type="number"id="${ruleId}-rate"class="simple-inputtext"style="width: 90px;"min="0"step="0.1"value="1.0"><span>%</span></div>`;return;}
if(type==='all_after'){fields.innerHTML=`<div class="rule-range-line"><input type="number"id="${ruleId}-threshold"class="simple-inputtext"style="width: 90px;"min="1"step="1"value="10"><span>回以上使うと一律</span><input type="number"id="${ruleId}-rate"class="simple-inputtext"style="width: 90px;"min="0"step="0.1"value="1.0"><span>%</span></div>`;return;}
fields.innerHTML=`<div class="rule-range-line"><input type="number"id="${ruleId}-count"class="simple-inputtext"style="width: 90px;"min="1"step="1"value="1"><span>回まで</span><input type="number"id="${ruleId}-rate"class="simple-inputtext"style="width: 90px;"min="0"step="0.1"value="0"><span>%</span></div>`;}
function toggleRuleOpenEnd(ruleId){const checked=document.getElementById(ruleId+'-open').checked;const endInput=document.getElementById(ruleId+'-end');if(!endInput){return;}
endInput.disabled=checked;if(checked){endInput.value='';}else if(!endInput.value){const start=parseInt(document.getElementById(ruleId+'-start').value,10);endInput.value=isNaN(start)?1:start;}}
function calculatePoints(){let input;try{input=collectCalculationInput();}catch(error){alert(error.message);return;}
const result=buildCalculationResult(input.amountRanges,input.baseRate,input.rules,input.roundingMode);displayResult(result);saveToHistory({timestamp:new Date().toLocaleString('ja-JP'),amountRanges:input.amountRanges,baseRate:input.baseRate,rules:input.rules,roundingMode:input.roundingMode,result:result});}
function collectCalculationInput(){const amountRangeRows=collectAmountRanges();const baseRate=parseFloat(document.getElementById('base-rate').value);const roundingMode=document.getElementById('rounding-mode').value;if(isNaN(baseRate)||baseRate<0){throw new Error('基本還元率を0以上の数値で入力してください。');}
return{amountRanges:amountRangeRows,baseRate:baseRate,roundingMode:roundingMode,rules:collectRules()};}
function collectAmountRanges(){const rows=document.querySelectorAll('#amount-list tr');const ranges=[];let expectedStart=1;rows.forEach(function(row,index){const mode=document.getElementById(row.id+'-mode').value;const amount=parseFloat(document.getElementById(row.id+'-amount').value);let start;let end;if(mode==='range'){start=parseInt(document.getElementById(row.id+'-start').value,10);end=parseInt(document.getElementById(row.id+'-end').value,10);if(isNaN(start)||start<1){throw new Error('利用金額の'+(index+1)+'件目の開始回数を正しく入力してください。');}
if(isNaN(end)||end<start){throw new Error('利用金額の'+(index+1)+'件目の終了回数を正しく入力してください。');}
if(start!==expectedStart){throw new Error('利用金額の回数範囲に重複または空きがあります。連続するように入力してください。');}}else{const count=parseInt(document.getElementById(row.id+'-count-input').value,10);if(isNaN(count)||count<1){throw new Error('利用金額の'+(index+1)+'件目の回数を正しく入力してください。');}
start=expectedStart;end=expectedStart+count-1;}
if(isNaN(amount)||amount<=0){throw new Error('利用金額の'+(index+1)+'件目の金額を正しく入力してください。');}
ranges.push({start:start,end:end,amount:amount});expectedStart=end+1;});if(ranges.length===0){throw new Error('利用金額を1件以上入力してください。');}
return ranges;}
function collectRules(){const rows=document.querySelectorAll('#rule-list tr');const rules=[];rows.forEach(function(row,index){const id=row.id;const type=document.getElementById(id+'-type').value;const rate=parseFloat(document.getElementById(id+'-rate').value);if(isNaN(rate)||rate<0){throw new Error('パターン'+(index+1)+'の還元率を正しく入力してください。');}
if(type==='range'){const start=parseInt(document.getElementById(id+'-start').value,10);const open=document.getElementById(id+'-open').checked;const endValue=document.getElementById(id+'-end').value;const end=open?Infinity:parseInt(endValue,10);if(isNaN(start)||start<1){throw new Error('パターン'+(index+1)+'の開始回数を正しく入力してください。');}
if(!open&&(isNaN(end)||end<start)){throw new Error('パターン'+(index+1)+'の終了回数を正しく入力してください。');}
rules.push({type:type,start:start,end:end,rate:rate});return;}
if(type==='all_after'){const threshold=parseInt(document.getElementById(id+'-threshold').value,10);if(isNaN(threshold)||threshold<1){throw new Error('パターン'+(index+1)+'の利用回数条件を正しく入力してください。');}
rules.push({type:type,threshold:threshold,rate:rate});return;}
const count=parseInt(document.getElementById(id+'-count').value,10);if(isNaN(count)||count<1){throw new Error('パターン'+(index+1)+'の回数を正しく入力してください。');}
rules.push({type:type,count:count,rate:rate});});return rules;}
function buildCalculationResult(amountRanges,baseRate,rules,roundingMode){const totalCount=amountRanges[amountRanges.length-1].end;const occurrences=expandOccurrences(amountRanges,baseRate,totalCount);const allAfterCandidates=rules.filter(function(rule){return rule.type==='all_after'&&totalCount>=rule.threshold;});if(allAfterCandidates.length>0){const globalRule=allAfterCandidates.sort(function(a,b){return b.threshold-a.threshold;})[0];occurrences.forEach(function(item){item.rate=globalRule.rate;item.reason=globalRule.threshold+'回以上使うと一律 '+formatRate(globalRule.rate)+'%';});}else{rules.forEach(function(rule){if(rule.type==='first_n'){occurrences.forEach(function(item){if(item.count<=rule.count){item.rate=rule.rate;item.reason='最初の'+rule.count+'回分は '+formatRate(rule.rate)+'%';}});return;}
if(rule.type==='range'){occurrences.forEach(function(item){if(item.count>=rule.start&&item.count<=rule.end){item.rate=rule.rate;item.reason=describeRule(rule);}});}});}
occurrences.forEach(function(item){item.rawPoint=item.amount*item.rate/100;item.point=roundPoint(item.rawPoint,roundingMode);});const detailRows=mergeOccurrences(occurrences);const totalAmount=occurrences.reduce(function(sum,item){return sum+item.amount;},0);const totalPoints=occurrences.reduce(function(sum,item){return sum+item.point;},0);return{totalCount:totalCount,totalAmount:totalAmount,totalPoints:totalPoints,baseRate:baseRate,roundingMode:roundingMode,rules:rules,detailRows:detailRows};}
function expandOccurrences(amountRanges,baseRate,totalCount){const occurrences=[];for(let count=1;count<=totalCount;count+=1){const range=amountRanges.find(function(item){return count>=item.start&&count<=item.end;});occurrences.push({count:count,amount:range.amount,rate:baseRate,point:0,rawPoint:0,reason:'基本還元率 '+formatRate(baseRate)+'%'});}
return occurrences;}
function mergeOccurrences(occurrences){const rows=[];occurrences.forEach(function(item){const previous=rows[rows.length-1];if(previous&&previous.end+1===item.count&&previous.amount===item.amount&&previous.rate===item.rate&&previous.reason===item.reason&&previous.pointPerUse===item.point){previous.end=item.count;previous.times+=1;previous.subtotalAmount+=item.amount;previous.subtotalPoint+=item.point;return;}
rows.push({start:item.count,end:item.count,times:1,amount:item.amount,rate:item.rate,pointPerUse:item.point,subtotalAmount:item.amount,subtotalPoint:item.point,reason:item.reason});});return rows;}
function roundPoint(value,mode){if(mode==='ceil'){return Math.ceil(value);}
if(mode==='round'){return Math.round(value);}
return Math.floor(value);}
function displayResult(result){const resultDisplay=document.getElementById('result-display');const resultContent=document.getElementById('result-content');const rulesHtml=result.rules.length===0?'<p>追加パターンなし</p>':'<ul style="padding-left: 20px; margin: 0;">'+result.rules.map(function(rule){return'<li>'+describeRule(rule)+'</li>';}).join('')+'</ul>';const rowsHtml=result.detailRows.map(function(row){return`<tr><td>${formatRange(row.start,row.end)}</td><td>${formatNumber(row.amount)}円</td><td>${row.times}回</td><td>${formatRate(row.rate)}%</td><td>${formatNumber(row.pointPerUse)}pt</td><td>${formatNumber(row.subtotalPoint)}pt</td><td>${row.reason}</td></tr>`;}).join('');resultContent.innerHTML=`<p><strong>合計利用回数:</strong>${formatNumber(result.totalCount)}回</p><p><strong>合計利用金額:</strong>${formatNumber(result.totalAmount)}円</p><p><strong>端数処理:</strong>${describeRoundingMode(result.roundingMode)}</p><p><strong>適用パターン:</strong></p>${rulesHtml}<p><strong>獲得ポイント:</strong>${formatNumber(result.totalPoints)}ポイント</p><table class="result-table"><thead><tr><th>対象回数</th><th>利用金額</th><th>回数</th><th>還元率</th><th>1回あたり</th><th>小計</th><th>適用理由</th></tr></thead><tbody>${rowsHtml}</tbody></table>`;resultDisplay.style.display='block';resultDisplay.scrollIntoView({behavior:'smooth',block:'start'});}
function saveToHistory(entry){let history=JSON.parse(localStorage.getItem(HISTORY_KEY)||'[]');history.unshift(entry);if(history.length>30){history=history.slice(0,30);}
localStorage.setItem(HISTORY_KEY,JSON.stringify(history));loadHistory();}
function loadHistory(){const historyList=document.getElementById('history-list');const history=JSON.parse(localStorage.getItem(HISTORY_KEY)||'[]');if(!historyList){return;}
if(history.length===0){historyList.innerHTML='<p style="text-align: center; padding: 20px;">まだ計算履歴がありません</p>';return;}
historyList.innerHTML=history.map(function(item,index){return`<div class="history-item"><div style="display: flex; justify-content: space-between; gap: 10px; align-items: flex-start; flex-wrap: wrap;"><div style="flex: 1;"><div style="font-size: 12px;">${item.timestamp}</div><div style="font-weight: bold; margin-top: 4px;">${item.result.totalCount}回/${formatNumber(item.result.totalAmount)}円/${formatNumber(item.result.totalPoints)}ポイント</div><div style="font-size: 14px; margin-top: 6px;">基本還元率 ${formatRate(item.baseRate)}%/端数処理 ${describeRoundingMode(item.roundingMode)}</div></div><button type="button"class="round-rect-button small-button"onclick="deleteHistoryItem(${index})"><div class="middle-text">削除</div></button></div></div>`;}).join('');}
function deleteHistoryItem(index){const history=JSON.parse(localStorage.getItem(HISTORY_KEY)||'[]');history.splice(index,1);localStorage.setItem(HISTORY_KEY,JSON.stringify(history));loadHistory();}
function clearHistory(){const history=JSON.parse(localStorage.getItem(HISTORY_KEY)||'[]');if(history.length===0){alert('クリアする履歴がありません。');return;}
if(confirm('本当に履歴をすべて削除しますか？')){localStorage.removeItem(HISTORY_KEY);loadHistory();}}
function describeRule(rule){if(rule.type==='range'){if(rule.end===Infinity){return rule.start+'回目以降は '+formatRate(rule.rate)+'%';}
return rule.start+'回目から'+rule.end+'回目までは '+formatRate(rule.rate)+'%';}
if(rule.type==='all_after'){return rule.threshold+'回以上使うと一律 '+formatRate(rule.rate)+'%';}
return'最初の'+rule.count+'回分は '+formatRate(rule.rate)+'%';}
function describeRoundingMode(mode){if(mode==='ceil'){return'切り上げ';}
if(mode==='round'){return'四捨五入';}
return'切り捨て';}
function formatRange(start,end){if(start===end){return start+'回目';}
return start+'回目から'+end+'回目';}
function formatRate(value){const rounded=Math.round(value*1000)/1000;return rounded.toLocaleString('ja-JP',{minimumFractionDigits:rounded%1===0?0:1,maximumFractionDigits:3});}
function formatNumber(value){return value.toLocaleString('ja-JP');}
